    LOGGER.info(
        "Dispatching %d invites (%d newly assigned codes, %d reused)",
        len(assignments),
        len(new_assignments),
        len(assignments) - len(new_assignments),
    )

    failures: List[Tuple[str, str]] = []
    for email, code in assignments:
